<?php $pageTitle='رسائل التواصل'; include __DIR__.'/includes/header.php'; $pdo=getDB();
if($_SERVER['REQUEST_METHOD']==='POST' && adminTableExists($pdo,'contacts')){$pdo->prepare('UPDATE contacts SET status=? WHERE id=?')->execute([$_POST['status'],(int)$_POST['id']]);}
$items=adminTableExists($pdo,'contacts')?adminFetchAll($pdo,'SELECT * FROM contacts ORDER BY created_at DESC'):[];?>
<div class="container-fluid"><h1 class="h4">إدارة الرسائل</h1><table class="table table-sm table-bordered"><tr><th>#</th><th>الاسم</th><th>البريد</th><th>النوع</th><th>الحالة</th><th>إجراء</th></tr><?php foreach($items as $i):?><tr><td><?php echo $i['id'];?></td><td><?php echo escape($i['name']);?></td><td><?php echo escape($i['email']);?></td><td><?php echo escape($i['inquiry_type']);?></td><td><?php echo escape($i['status']);?></td><td><form method="post" class="d-flex gap-1"><input type="hidden" name="id" value="<?php echo $i['id'];?>"><select name="status" class="form-select form-select-sm"><option>unread</option><option>read</option><option>processed</option></select><button class="btn btn-sm btn-outline-primary">تحديث</button></form></td></tr><?php endforeach;?></table></div>
